const resp = $.steps.readProspects.response || {};
const values = resp.values || [];
if (values.length < 2) return { prospects: [], count: 0 };
const headers = values[0];
const prospects = values.slice(1).map((row, i) => ({
  index: i + 1,
  name: row[0] || 'Unknown',
  email: row[1] || '',
  socialUrl: row[2] || '',
  company: row[3] || ''
})).filter(p => p.email.length > 0);
return { prospects: prospects.slice(0, 10), count: prospects.length };

const prospects = $.steps.parseProspects.output.prospects || [];
const iterations = $.steps.scrapeProfiles.response.iterations || [];
let compiled = '';
prospects.forEach((p, i) => {
  compiled += '--- PROSPECT ' + p.index + ': ' + p.name + ' ---\n';
  compiled += 'Email: ' + p.email + '\n';
  compiled += 'Company: ' + p.company + '\n';
  compiled += 'Social URL: ' + p.socialUrl + '\n';
  if (iterations[i] && iterations[i].scrapeOne && iterations[i].scrapeOne.response) {
    const s = iterations[i].scrapeOne.response;
    const content = s.data ? (s.data.markdown || s.data.content || '') : (typeof s === 'string' ? s : JSON.stringify(s));
    compiled += 'Social Content: ' + content.slice(0, 2000) + '\n';
  }
  compiled += '\n';
});
return { compiled: compiled.slice(0, 25000), count: prospects.length };

const d = $.steps.compileProfiles.output;
const company = $.input.companyName;
const vp = $.input.valueProposition;
const sender = $.input.senderName;
let prompt = 'You are an expert sales copywriter. Analyze each prospect social media presence and write a personalized outreach email.\n\n';
prompt += 'YOUR COMPANY: ' + company + '\n';
prompt += 'VALUE PROPOSITION: ' + vp + '\n';
prompt += 'SENDER: ' + sender + '\n\n';
prompt += 'PROSPECTS:\n' + d.compiled + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write a unique, personalized email for each prospect\n';
prompt += '- Reference specific details from their social media\n';
prompt += '- Keep emails under 150 words, warm and professional\n';
prompt += '- Include a clear CTA\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "emails": [{\n';
prompt += '    "name": "prospect name",\n';
prompt += '    "email": "prospect email",\n';
prompt += '    "subject": "email subject line",\n';
prompt += '    "body": "email body text",\n';
prompt += '    "personalNote": "what was personalized and why"\n';
prompt += '  }],\n';
prompt += '  "campaignSummary": "summary of email campaign"\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { emails: [], campaignSummary: raw }; }

const ai = $.steps.parseAI.output;
const emails = ai.emails || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Campaign Generated', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + emails.length + ' personalized emails* ready to send' } });

if (ai.campaignSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.campaignSummary.slice(0, 500) } });
}

emails.slice(0, 5).forEach(e => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (e.name || 'Unknown') + '* - ' + (e.subject || 'No Subject').slice(0, 60) } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Firecrawl + Claude AI + Gmail' }] });

const fallback = 'Email Campaign: ' + emails.length + ' personalized emails generated';
return { blocks, fallback };
